var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 근처야.","JPN":"この辺りだ。","ENG":"It should be around here.","TWN":"就是這附近了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"근처라고요? 딱히 시신은 보이지 않는 것 같은데…","JPN":"この辺りですか？　遺体はどこにも見当たらないんですが……","ENG":"We're close? I don't see any bodies...","TWN":"這附近？可我沒看到有屍體啊……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"찾았다.","JPN":"見つけた。","ENG":"Found it.","TWN":"找到了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"그건… 돌로 된 곤충이잖아요?","JPN":"これは……石化した虫ですよね？","ENG":"That's... just a bug made of stone.","TWN":"那是……昆蟲化石吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이면세계의 생물 화석은 귀해. 이런 거에 환장하는 수집가들이 많거든.","JPN":"裏世界の化石は貴重だ。こういったものに目がないコレクターはたくさんいるからさ。","ENG":"Fossils from Counterside are rare. Many collectors would pay a good amount for something like this.","TWN":"來自異界的生物化石非常罕見。有很多收藏家對這種東西非常癡迷。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"예? 이런 화석은 저희 미션과 전혀 상관없지 않나요?","JPN":"え？　ミッションとこの化石は全くの無関係なんじゃ……？","ENG":"What? Isn't this fossil unrelated to our mission?","TWN":"是嗎？可是這些化石與我們的任務完全無關啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"좋은 장비로 오래 살아남으려면 부수익은 선택사항이 아니야.","JPN":"いい装備を使いながら長く生き残ろうと思ったら、こういう副収入を得るのは必須だ。","ENG":"Side hustles aren't an option if you want to be using high-quality equipment that'll keep you alive.","TWN":"如果想靠優良的裝備來提升生存能力，那副業收入就是必備選項。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 정직한 기업 졸개 마인드로는 이 바닥에서 일 년도 못 버텨, 초짜 오클랜드 씨.","JPN":"真面目なだけの会社員の態度じゃ、この業界では1年も持たないよ、新米のオークランドさん。","ENG":"You won't last a year in this line of work as a goody-two-shoes worker, Oakland.","TWN":"就憑你這種老實的社畜，在這裡，你連一年都堅持不了，菜鳥奧克蘭先生。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"…가, 같이 가요! 혼자선 위험합니다!","JPN":"……ま、待ってください！　お一人では危ないですよ！","ENG":"...Hey, wait for me! It's dangerous going alone!","TWN":"呃……等、等等我！一個人很危險的！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"이건… 대체…?","JPN":"これはいったい……？","ENG":"What... is this...?","TWN":"這……到底是……？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"ID 태그 일치. 기업에서 보낸 탐사대가 맞아.","JPN":"IDタグが一致する。企業が派遣した探索部隊の者で間違いない。","ENG":"ID tags check out. They are the exploration team the company sent.","TWN":"ID標籤匹配。沒錯，就是公司派來的勘查隊。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"사람이 무슨 일을 당해야 이런 꼴이 되는 거죠?","JPN":"いったいこの人に何があったんですか？　こんな姿になるなんて。","ENG":"How does someone end up like this?","TWN":"到底是經歷什麼才會變成這樣……？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"감식을 해보기 전까진 알 수 없겠지만…","JPN":"鑑識をしてみるまではわからないけど……","ENG":"Guess we won't know for sure until we identify them, but...","TWN":"在檢測出來前我們也無法知曉，但……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"상반신만 10마일 떨어진 곳에서 발견된 걸 보면 침식체 짓이겠네.","JPN":"上半身が10マイル離れたところにあった時点で、侵食体の仕業で間違いない。","ENG":"seeing how the legs and torsos are 10 miles apart, it must be a C.O.","TWN":"既然上半身是在十英里外發現的，那這肯定是侵蝕體造成的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"속이… 별로 안 좋은데요.","JPN":"少し……気持ちが悪くなりました。","ENG":"I... don't feel so good.","TWN":"我……有點想吐。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"수트에는 토하지 마. 그거 세탁 안 되니까.","JPN":"スーツの中で吐かないで。洗濯不可だから、そのスーツ。","ENG":"Don't hurl in the suit because you can't wash it.","TWN":"不要吐在防護服裡，會洗不掉的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"남은 태그랑 블랙박스만 회수해. 그럼 임무는 끝이야.","JPN":"残ったタグとブラックボックスを回収して、それで任務は終わり。","ENG":"Just grab the tags and black box. Then our mission here is done.","TWN":"再回收下剩餘的標籤和黑盒。任務就結束了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"알겠습니다, 그럼…","JPN":"わかりました。では……","ENG":"Copy that. Then...","TWN":"知道了，那麼……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"<color=#ffd34c>여긴… 사대… 있나?</color>","JPN":"<color=#ffd34c>こちら……索隊……いるか？</color>","ENG":"<color=#ffd34c>This is... –dition... copy?</color>","TWN":"<color=#ffd34c>這裡是……勘……隊……有人嗎？</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"무전 소리…?","JPN":"これは、無線の音……？","ENG":"Radio comms...?","TWN":"無線電的聲音……？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"비상용 통신망이군요.","JPN":"非常用の通信網のようです。","ENG":"It's the emergency comms.","TWN":"這是緊急通訊網。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"잠시만요. 주파수를 맞춰보겠습니다.","JPN":"ちょっと待ってくださいね、周波数を合わせてみます。","ENG":"Hold on. Let me find the frequency.","TWN":"等我一下。我來調整下頻率。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"여긴…! 스티플 제이슨 탐사대다! 누구 듣고 있나?!","JPN":"こちら……探索部隊のスティープル・ジェイソンだ！　誰かいないか！？","ENG":"This is...! Stipple Jason Expedition! Does anyone copy?!","TWN":"這裡是……！史蒂芬·傑森勘查隊！有人在聽嗎？！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUND_FLOOR_NULL_NOISE","text":{"KOREA":"신원미상의 적으로부터 습격당했어! 누구라도 좋으니 좀 살려줘!","JPN":"正体不明の敵から襲撃を受けた！　誰でもいい、助けてくれ！","ENG":"We've been ambushed by an unidentified enemy! Please, anyone, help us!","TWN":"我們遭遇不明敵襲！有沒有人可以來救救我們！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"발신지 잡혔습니다. 좌표는…","JPN":"発信源を特定しました。座標は……","ENG":"I triangulated the transmission. The coordinates are...","TWN":"已識別發訊地址。座標是……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_NEWBIE","text":{"KOREA":"1.147, 1.125, 109.425…","JPN":"1.147, 1.125, 109.425…","ENG":"1.147, 1.125, 109.425...","TWN":"1147，1125，109425……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_NEWBIE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};